Боб каждое утро бросает честную шестигранную кость. Если выпадет составное число, он завтракает сладкой кашей. Если выпадет простое число — несладкой кашей. Когда выпадает единица, он бросает кость заново. Найди ожидаемое значение разности между количеством дней в невисокосном году, когда Боб ест несладкую кашу, и количеством дней, когда он ест сладкую кашу. [asy]
import olympiad; import geometry; size(50);

defaultpen(linewidth(0.8));
draw(unitsquare);
draw((0,1)--(0.5,1.5)--(1.5,1.5)--(1.5,0.5)--(1,0)^^(1.5,1.5)--(1,1));
dot((0.3,0.2)); dot((0.7,0.2));
dot((0.3,0.5)); dot((0.7,0.5));
dot((0.3,0.8)); dot((0.7,0.8));
dot((1.125,0.375)); dot((1.25,0.75)); dot((1.375,1.125));
dot((0.5,0.5/3 + 1)); dot((1.0,4/3));
[/asy]

